import{_ as n,c as a,o as p,a1 as e}from"./chunks/framework.TuIRSVI8.js";const m=JSON.parse('{"title":"Dotfiles Architecture Guide","description":"","frontmatter":{},"headers":[],"relativePath":"ARCHITECTURE_VISUAL.md","filePath":"ARCHITECTURE_VISUAL.md","lastUpdated":1765863345000}'),l={name:"ARCHITECTURE_VISUAL.md"};function i(t,s,c,o,r,d){return p(),a("div",null,[...s[0]||(s[0]=[e(`<h1 id="dotfiles-architecture-guide" tabindex="-1">Dotfiles Architecture Guide <a class="header-anchor" href="#dotfiles-architecture-guide" aria-label="Permalink to &quot;Dotfiles Architecture Guide&quot;">​</a></h1><p><strong>Visual guide to system structure and data flow</strong></p><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ol><li><a href="#high-level-overview">High-Level Overview</a></li><li><a href="#directory-structure">Directory Structure</a></li><li><a href="#data-flow">Data Flow</a></li><li><a href="#loading-order">Loading Order</a></li><li><a href="#component-interaction">Component Interaction</a></li><li><a href="#edit-deploy-workflow">Edit-Deploy Workflow</a></li></ol><hr><h2 id="high-level-overview" tabindex="-1">High-Level Overview <a class="header-anchor" href="#high-level-overview" aria-label="Permalink to &quot;High-Level Overview&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                     DOTFILES ECOSYSTEM                          │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                                                                 │</span></span>
<span class="line"><span>│  ┌──────────────────┐           ┌──────────────────┐          │</span></span>
<span class="line"><span>│  │   SOURCE REPO    │           │     DEPLOYED     │          │</span></span>
<span class="line"><span>│  │  (editable)      │  chezmoi  │   (read-only)    │          │</span></span>
<span class="line"><span>│  │                  │  ──────&gt;  │                  │          │</span></span>
<span class="line"><span>│  │  ~/.local/share/ │  apply    │  ~/.config/zsh/  │          │</span></span>
<span class="line"><span>│  │  chezmoi/        │           │  ~/.gitconfig    │          │</span></span>
<span class="line"><span>│  └──────────────────┘           └──────────────────┘          │</span></span>
<span class="line"><span>│         │                                 │                    │</span></span>
<span class="line"><span>│         │                                 │                    │</span></span>
<span class="line"><span>│         │ git                             │ source             │</span></span>
<span class="line"><span>│         │ push/pull                       │                    │</span></span>
<span class="line"><span>│         │                                 │                    │</span></span>
<span class="line"><span>│         ▼                                 ▼                    │</span></span>
<span class="line"><span>│  ┌──────────────────┐           ┌──────────────────┐          │</span></span>
<span class="line"><span>│  │  GitHub Remote   │           │   Zsh Shell      │          │</span></span>
<span class="line"><span>│  │  Backup &amp; Sync   │           │   Runtime        │          │</span></span>
<span class="line"><span>│  └──────────────────┘           └──────────────────┘          │</span></span>
<span class="line"><span>│                                                                 │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Purpose</th><th>Location</th></tr></thead><tbody><tr><td><strong>Source Repo</strong></td><td>Where you edit</td><td><code>~/.local/share/chezmoi/</code></td></tr><tr><td><strong>Deployed Files</strong></td><td>What shell uses</td><td><code>~/.config/zsh/</code>, <code>~/</code>, etc.</td></tr><tr><td><strong>chezmoi</strong></td><td>Deployment tool</td><td>Manages source → deployed sync</td></tr><tr><td><strong>Git</strong></td><td>Version control</td><td>Backs up source repo</td></tr></tbody></table><hr><h2 id="directory-structure" tabindex="-1">Directory Structure <a class="header-anchor" href="#directory-structure" aria-label="Permalink to &quot;Directory Structure&quot;">​</a></h2><h3 id="complete-tree-view" tabindex="-1">Complete Tree View <a class="header-anchor" href="#complete-tree-view" aria-label="Permalink to &quot;Complete Tree View&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$HOME/</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── .local/share/chezmoi/          ← SOURCE REPOSITORY (EDIT HERE!)</span></span>
<span class="line"><span>│   │</span></span>
<span class="line"><span>│   ├── .git/                      ← Git version control</span></span>
<span class="line"><span>│   ├── .github/                   ← CI/CD workflows</span></span>
<span class="line"><span>│   │   └── workflows/</span></span>
<span class="line"><span>│   │       └── test.yml           (Automated testing)</span></span>
<span class="line"><span>│   │</span></span>
<span class="line"><span>│   ├── private_dot_config/        ← Will deploy to ~/.config/</span></span>
<span class="line"><span>│   │   └── zsh/</span></span>
<span class="line"><span>│   │       ├── dot_zshrc          ├─► ~/.config/zsh/.zshrc</span></span>
<span class="line"><span>│   │       │</span></span>
<span class="line"><span>│   │       ├── config/            ← Core configuration</span></span>
<span class="line"><span>│   │       │   ├── 00-environment.zsh    (PATH, XDG, exports)</span></span>
<span class="line"><span>│   │       │   ├── 05-shell-options.zsh  (history, options)</span></span>
<span class="line"><span>│   │       │   ├── 10-omz.zsh            (Oh-My-Zsh)</span></span>
<span class="line"><span>│   │       │   ├── 20-plugins.zsh        (fzf, gh, direnv)</span></span>
<span class="line"><span>│   │       │   ├── 30-completions.zsh    (completion system)</span></span>
<span class="line"><span>│   │       │   ├── 40-prompt.zsh         (Powerlevel10k)</span></span>
<span class="line"><span>│   │       │   └── 99-welcome.zsh        (welcome message)</span></span>
<span class="line"><span>│   │       │</span></span>
<span class="line"><span>│   │       ├── aliases/           ← Command shortcuts</span></span>
<span class="line"><span>│   │       │   ├── common.zsh             (general)</span></span>
<span class="line"><span>│   │       │   ├── git.zsh                (git)</span></span>
<span class="line"><span>│   │       │   ├── docker.zsh             (docker)</span></span>
<span class="line"><span>│   │       │   ├── kubectl.zsh            (kubernetes)</span></span>
<span class="line"><span>│   │       │   ├── gh.zsh                 (GitHub CLI)</span></span>
<span class="line"><span>│   │       │   └── rust-tools.zsh         (bat, eza, etc.)</span></span>
<span class="line"><span>│   │       │</span></span>
<span class="line"><span>│   │       ├── functions/         ← Custom functions</span></span>
<span class="line"><span>│   │       │   ├── dotfiles-helper.zsh    (dotfiles command)</span></span>
<span class="line"><span>│   │       │   ├── smart-wrappers.zsh     (bat, ls, cd, man)</span></span>
<span class="line"><span>│   │       │   ├── python-dev.zsh         (pyinit, venv)</span></span>
<span class="line"><span>│   │       │   ├── node-dev.zsh           (nodeinit, npmup)</span></span>
<span class="line"><span>│   │       │   ├── polyglot-dev.zsh       (go, rust, etc.)</span></span>
<span class="line"><span>│   │       │   ├── git-utils.zsh          (fshow, fco)</span></span>
<span class="line"><span>│   │       │   └── system.zsh             (mkcd, path)</span></span>
<span class="line"><span>│   │       │</span></span>
<span class="line"><span>│   │       ├── os/                ← Platform-specific</span></span>
<span class="line"><span>│   │       │   ├── darwin.zsh             (macOS)</span></span>
<span class="line"><span>│   │       │   ├── linux.zsh              (Linux)</span></span>
<span class="line"><span>│   │       │   └── wsl.zsh                (WSL)</span></span>
<span class="line"><span>│   │       │</span></span>
<span class="line"><span>│   │       └── private/           ← Secrets (templates)</span></span>
<span class="line"><span>│   │           └── secrets.zsh.tmpl       (1Password)</span></span>
<span class="line"><span>│   │</span></span>
<span class="line"><span>│   ├── dot_claude/                ← Autonomous agents</span></span>
<span class="line"><span>│   │   ├── agents/                        (maintenance, security)</span></span>
<span class="line"><span>│   │   ├── skills/                        (zsh-expert, etc.)</span></span>
<span class="line"><span>│   │   ├── commands/                      (slash commands)</span></span>
<span class="line"><span>│   │   └── preferences.yml                (learning system)</span></span>
<span class="line"><span>│   │</span></span>
<span class="line"><span>│   ├── docs/                      ← Documentation</span></span>
<span class="line"><span>│   │   ├── QUICKSTART.md</span></span>
<span class="line"><span>│   │   ├── ARCHITECTURE_VISUAL.md         (this file)</span></span>
<span class="line"><span>│   │   ├── SSH_AUTH.md</span></span>
<span class="line"><span>│   │   ├── SETUP.md</span></span>
<span class="line"><span>│   │   └── ...</span></span>
<span class="line"><span>│   │</span></span>
<span class="line"><span>│   ├── tests/                     ← Test suite (bats)</span></span>
<span class="line"><span>│   │   ├── unit/</span></span>
<span class="line"><span>│   │   ├── integration/</span></span>
<span class="line"><span>│   │   └── fixtures/</span></span>
<span class="line"><span>│   │</span></span>
<span class="line"><span>│   ├── CLAUDE.md                  ← AI instructions</span></span>
<span class="line"><span>│   ├── README.md                  ← Main documentation</span></span>
<span class="line"><span>│   └── install.sh                 ← Bootstrap script</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── .config/zsh/                   ← DEPLOYED FILES (READ-ONLY!)</span></span>
<span class="line"><span>│   ├── .zshrc                     (Auto-managed by chezmoi)</span></span>
<span class="line"><span>│   ├── config/                    (Same structure as source)</span></span>
<span class="line"><span>│   ├── aliases/</span></span>
<span class="line"><span>│   ├── functions/</span></span>
<span class="line"><span>│   ├── os/</span></span>
<span class="line"><span>│   └── private/</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>├── .claude/                       ← Agent system (deployed)</span></span>
<span class="line"><span>│   ├── agents/</span></span>
<span class="line"><span>│   └── skills/</span></span>
<span class="line"><span>│</span></span>
<span class="line"><span>└── .gitconfig                     ← Git config (deployed)</span></span></code></pre></div><h3 id="naming-convention" tabindex="-1">Naming Convention <a class="header-anchor" href="#naming-convention" aria-label="Permalink to &quot;Naming Convention&quot;">​</a></h3><p>chezmoi uses special prefixes for file naming:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Deployed As</th><th>Example</th></tr></thead><tbody><tr><td><code>dot_</code></td><td><code>.</code></td><td><code>dot_zshrc</code> → <code>.zshrc</code></td></tr><tr><td><code>private_</code></td><td>(no prefix)</td><td><code>private_dot_config</code> → <code>.config/</code></td></tr><tr><td><code>.tmpl</code></td><td>(processed)</td><td><code>secrets.zsh.tmpl</code> → <code>secrets.zsh</code></td></tr></tbody></table><hr><h2 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h2><h3 id="source-to-deployment" tabindex="-1">Source to Deployment <a class="header-anchor" href="#source-to-deployment" aria-label="Permalink to &quot;Source to Deployment&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                      DATA FLOW DIAGRAM                          │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  1. EDIT SOURCE</span></span>
<span class="line"><span>  ┌───────────────────────────────────────┐</span></span>
<span class="line"><span>  │ ~/.local/share/chezmoi/               │</span></span>
<span class="line"><span>  │   private_dot_config/zsh/             │</span></span>
<span class="line"><span>  │     aliases/common.zsh                │</span></span>
<span class="line"><span>  └───────────────────────────────────────┘</span></span>
<span class="line"><span>           │</span></span>
<span class="line"><span>           │ chezmoi diff (preview)</span></span>
<span class="line"><span>           │</span></span>
<span class="line"><span>           ▼</span></span>
<span class="line"><span>  2. PREVIEW CHANGES</span></span>
<span class="line"><span>  ┌───────────────────────────────────────┐</span></span>
<span class="line"><span>  │ Shows:                                │</span></span>
<span class="line"><span>  │   + Added lines                       │</span></span>
<span class="line"><span>  │   - Removed lines                     │</span></span>
<span class="line"><span>  │   ~ Modified lines                    │</span></span>
<span class="line"><span>  └───────────────────────────────────────┘</span></span>
<span class="line"><span>           │</span></span>
<span class="line"><span>           │ chezmoi apply (deploy)</span></span>
<span class="line"><span>           │</span></span>
<span class="line"><span>           ▼</span></span>
<span class="line"><span>  3. DEPLOY TO SYSTEM</span></span>
<span class="line"><span>  ┌───────────────────────────────────────┐</span></span>
<span class="line"><span>  │ ~/.config/zsh/aliases/common.zsh      │</span></span>
<span class="line"><span>  │                                       │</span></span>
<span class="line"><span>  │ ⚠️  Read-only, managed by chezmoi     │</span></span>
<span class="line"><span>  └───────────────────────────────────────┘</span></span>
<span class="line"><span>           │</span></span>
<span class="line"><span>           │ source ~/.config/zsh/.zshrc</span></span>
<span class="line"><span>           │ (or: exec zsh)</span></span>
<span class="line"><span>           │</span></span>
<span class="line"><span>           ▼</span></span>
<span class="line"><span>  4. SHELL USES DEPLOYED FILES</span></span>
<span class="line"><span>  ┌───────────────────────────────────────┐</span></span>
<span class="line"><span>  │ Zsh Shell                             │</span></span>
<span class="line"><span>  │   ✅ New aliases available            │</span></span>
<span class="line"><span>  │   ✅ Functions loaded                 │</span></span>
<span class="line"><span>  └───────────────────────────────────────┘</span></span></code></pre></div><h3 id="version-control-flow" tabindex="-1">Version Control Flow <a class="header-anchor" href="#version-control-flow" aria-label="Permalink to &quot;Version Control Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  LOCAL SOURCE                 REMOTE REPOSITORY</span></span>
<span class="line"><span>  ┌─────────────┐              ┌─────────────┐</span></span>
<span class="line"><span>  │  Edit files │              │   GitHub    │</span></span>
<span class="line"><span>  └──────┬──────┘              └──────▲──────┘</span></span>
<span class="line"><span>         │                            │</span></span>
<span class="line"><span>         │ git add .                  │ git push</span></span>
<span class="line"><span>         │ git commit                 │</span></span>
<span class="line"><span>         │                            │</span></span>
<span class="line"><span>         ▼                            │</span></span>
<span class="line"><span>  ┌─────────────┐                     │</span></span>
<span class="line"><span>  │ Committed   │─────────────────────┘</span></span>
<span class="line"><span>  │ Changes     │</span></span>
<span class="line"><span>  └─────────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │ chezmoi apply</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>  ┌─────────────┐</span></span>
<span class="line"><span>  │ Deployed to │</span></span>
<span class="line"><span>  │ System      │</span></span>
<span class="line"><span>  └─────────────┘</span></span></code></pre></div><hr><h2 id="loading-order" tabindex="-1">Loading Order <a class="header-anchor" href="#loading-order" aria-label="Permalink to &quot;Loading Order&quot;">​</a></h2><h3 id="shell-initialization-sequence" tabindex="-1">Shell Initialization Sequence <a class="header-anchor" href="#shell-initialization-sequence" aria-label="Permalink to &quot;Shell Initialization Sequence&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                 ZSH INITIALIZATION FLOW                        │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  1. Powerlevel10k Instant Prompt</span></span>
<span class="line"><span>     ├─► Fast prompt rendering</span></span>
<span class="line"><span>     └─► ~/.cache/p10k-instant-prompt-*.zsh</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  2. Main .zshrc</span></span>
<span class="line"><span>     ├─► ~/.config/zsh/.zshrc</span></span>
<span class="line"><span>     └─► Orchestrates all other files</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  3. Core Configuration (in order)</span></span>
<span class="line"><span>     ├─► 00-environment.zsh      (PATH, XDG_CONFIG_HOME, exports)</span></span>
<span class="line"><span>     ├─► 05-shell-options.zsh    (HIST_SIZE, setopt, etc.)</span></span>
<span class="line"><span>     ├─► 10-omz.zsh              (Oh-My-Zsh initialization)</span></span>
<span class="line"><span>     ├─► 20-plugins.zsh          (fzf, gh, direnv, zoxide)</span></span>
<span class="line"><span>     ├─► 30-completions.zsh      (Completion system)</span></span>
<span class="line"><span>     ├─► 40-prompt.zsh           (Powerlevel10k config)</span></span>
<span class="line"><span>     └─► 99-welcome.zsh          (Welcome message)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  4. Aliases</span></span>
<span class="line"><span>     ├─► For each file in aliases/*.zsh:</span></span>
<span class="line"><span>     │   ├─► common.zsh</span></span>
<span class="line"><span>     │   ├─► git.zsh</span></span>
<span class="line"><span>     │   ├─► docker.zsh</span></span>
<span class="line"><span>     │   └─► ... (all .zsh files)</span></span>
<span class="line"><span>     └─► Loaded alphabetically</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  5. Functions</span></span>
<span class="line"><span>     ├─► For each file in functions/*.zsh:</span></span>
<span class="line"><span>     │   ├─► dotfiles-helper.zsh</span></span>
<span class="line"><span>     │   ├─► smart-wrappers.zsh</span></span>
<span class="line"><span>     │   ├─► python-dev.zsh</span></span>
<span class="line"><span>     │   └─► ... (all .zsh files)</span></span>
<span class="line"><span>     └─► Loaded alphabetically</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  6. OS-Specific Configuration</span></span>
<span class="line"><span>     ├─► Detect OS: uname -s</span></span>
<span class="line"><span>     ├─► If Darwin: source os/darwin.zsh</span></span>
<span class="line"><span>     ├─► If Linux + Microsoft: source os/wsl.zsh</span></span>
<span class="line"><span>     └─► If Linux: source os/linux.zsh</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  7. Private/Secrets</span></span>
<span class="line"><span>     ├─► Source private/secrets.zsh</span></span>
<span class="line"><span>     └─► 1Password integration, API keys</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  8. Custom User Config</span></span>
<span class="line"><span>     └─► If exists: source ~/.config/zsh/custom.zsh</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  9. Powerlevel10k Final Setup</span></span>
<span class="line"><span>     └─► Source ~/.p10k.zsh</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ ✅ Shell Ready!                                                │</span></span>
<span class="line"><span>│ All aliases, functions, and configurations loaded              │</span></span>
<span class="line"><span>└────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="why-this-order-matters" tabindex="-1">Why This Order Matters <a class="header-anchor" href="#why-this-order-matters" aria-label="Permalink to &quot;Why This Order Matters&quot;">​</a></h3><ol><li><strong>Environment First</strong> - PATH must be set before anything else</li><li><strong>Oh-My-Zsh Early</strong> - Framework must load before plugins</li><li><strong>Plugins After OMZ</strong> - Plugins depend on OMZ being initialized</li><li><strong>Aliases Before Functions</strong> - Functions can override aliases</li><li><strong>OS-Specific Last</strong> - Override defaults for specific platform</li><li><strong>Secrets Last</strong> - Private config can override public defaults</li></ol><hr><h2 id="component-interaction" tabindex="-1">Component Interaction <a class="header-anchor" href="#component-interaction" aria-label="Permalink to &quot;Component Interaction&quot;">​</a></h2><h3 id="how-components-work-together" tabindex="-1">How Components Work Together <a class="header-anchor" href="#how-components-work-together" aria-label="Permalink to &quot;How Components Work Together&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              COMPONENT INTERACTION DIAGRAM                      │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>           User Types Command</span></span>
<span class="line"><span>                   │</span></span>
<span class="line"><span>                   ▼</span></span>
<span class="line"><span>         ┌─────────────────┐</span></span>
<span class="line"><span>         │  Zsh Shell      │</span></span>
<span class="line"><span>         └────────┬────────┘</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>                  ├──────► Alias?  ─────► aliases/*.zsh</span></span>
<span class="line"><span>                  │                         ↓</span></span>
<span class="line"><span>                  │                       Execute</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>                  ├──────► Function? ───► functions/*.zsh</span></span>
<span class="line"><span>                  │                         ↓</span></span>
<span class="line"><span>                  │                       Execute</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>                  ├──────► Binary? ────► Check $PATH</span></span>
<span class="line"><span>                  │                         │</span></span>
<span class="line"><span>                  │                         ├─► ~/.local/bin</span></span>
<span class="line"><span>                  │                         ├─► /opt/homebrew/bin</span></span>
<span class="line"><span>                  │                         ├─► ~/.cargo/bin</span></span>
<span class="line"><span>                  │                         └─► /usr/bin</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>                  └──────► Not Found ───► command-not-found plugin</span></span>
<span class="line"><span>                                             ↓</span></span>
<span class="line"><span>                                           Suggest Package</span></span></code></pre></div><h3 id="example-pyinit-command" tabindex="-1">Example: <code>pyinit</code> Command <a class="header-anchor" href="#example-pyinit-command" aria-label="Permalink to &quot;Example: \`pyinit\` Command&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> User runs: pyinit myproject</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span> Zsh searches:</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─► Alias? ❌ Not found in aliases/*.zsh</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─► Function? ✅ Found in functions/python-dev.zsh</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─► Execute function:</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ├─► 1. Check if mise installed (graceful degradation)</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ├─► 2. Create project directory</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ├─► 3. Create .mise.toml with Python version</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ├─► 4. Create virtualenv (.venv)</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ├─► 5. Activate virtualenv</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         └─► 6. Install basic packages (pip, wheel, setuptools)</span></span></code></pre></div><hr><h2 id="edit-deploy-workflow" tabindex="-1">Edit-Deploy Workflow <a class="header-anchor" href="#edit-deploy-workflow" aria-label="Permalink to &quot;Edit-Deploy Workflow&quot;">​</a></h2><h3 id="complete-workflow-diagram" tabindex="-1">Complete Workflow Diagram <a class="header-anchor" href="#complete-workflow-diagram" aria-label="Permalink to &quot;Complete Workflow Diagram&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  EDIT-DEPLOY-TEST WORKFLOW                      │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  START</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>  ┌──────────────────────────────┐</span></span>
<span class="line"><span>  │ 1. DECIDE WHAT TO EDIT       │</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │ Run: dotfiles list           │</span></span>
<span class="line"><span>  │ Run: dotfiles docs arch      │</span></span>
<span class="line"><span>  └──────────────┬───────────────┘</span></span>
<span class="line"><span>                 │</span></span>
<span class="line"><span>                 ▼</span></span>
<span class="line"><span>  ┌──────────────────────────────┐</span></span>
<span class="line"><span>  │ 2. EDIT SOURCE FILE          │</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │ Option A:                    │</span></span>
<span class="line"><span>  │   dotfiles edit &lt;file&gt;       │</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │ Option B:                    │</span></span>
<span class="line"><span>  │   cd ~/.local/share/chezmoi  │</span></span>
<span class="line"><span>  │   vim private_dot_config/... │</span></span>
<span class="line"><span>  └──────────────┬───────────────┘</span></span>
<span class="line"><span>                 │</span></span>
<span class="line"><span>                 ▼</span></span>
<span class="line"><span>  ┌──────────────────────────────┐</span></span>
<span class="line"><span>  │ 3. PREVIEW CHANGES           │</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │ Run: chezmoi diff            │</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │ Review:                      │</span></span>
<span class="line"><span>  │   + Added lines              │</span></span>
<span class="line"><span>  │   - Removed lines            │</span></span>
<span class="line"><span>  │   ~ Modified lines           │</span></span>
<span class="line"><span>  └──────────────┬───────────────┘</span></span>
<span class="line"><span>                 │</span></span>
<span class="line"><span>                 ├─► Happy? ────► YES ──┐</span></span>
<span class="line"><span>                 │                       │</span></span>
<span class="line"><span>                 └─► NO ─────────────► (Edit again)</span></span>
<span class="line"><span>                                         │</span></span>
<span class="line"><span>  ┌──────────────────────────────────◄──┘</span></span>
<span class="line"><span>  │ 4. APPLY CHANGES             │</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │ Run: chezmoi apply           │</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │ Source files → Deployed      │</span></span>
<span class="line"><span>  └──────────────┬───────────────┘</span></span>
<span class="line"><span>                 │</span></span>
<span class="line"><span>                 ▼</span></span>
<span class="line"><span>  ┌──────────────────────────────┐</span></span>
<span class="line"><span>  │ 5. TEST IN SHELL             │</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │ Run: exec zsh                │</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │ Test: your-new-command       │</span></span>
<span class="line"><span>  └──────────────┬───────────────┘</span></span>
<span class="line"><span>                 │</span></span>
<span class="line"><span>                 ├─► Works? ────► YES ──┐</span></span>
<span class="line"><span>                 │                       │</span></span>
<span class="line"><span>                 └─► NO ─────────────► (Debug &amp; edit again)</span></span>
<span class="line"><span>                                         │</span></span>
<span class="line"><span>  ┌──────────────────────────────────◄──┘</span></span>
<span class="line"><span>  │ 6. COMMIT TO GIT             │</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │ cd ~/.local/share/chezmoi    │</span></span>
<span class="line"><span>  │ git add .                    │</span></span>
<span class="line"><span>  │ git commit -m &quot;...&quot;          │</span></span>
<span class="line"><span>  │ git push                     │</span></span>
<span class="line"><span>  └──────────────┬───────────────┘</span></span>
<span class="line"><span>                 │</span></span>
<span class="line"><span>                 ▼</span></span>
<span class="line"><span>  ┌──────────────────────────────┐</span></span>
<span class="line"><span>  │ 7. DONE! ✅                  │</span></span>
<span class="line"><span>  │                              │</span></span>
<span class="line"><span>  │ Changes:                     │</span></span>
<span class="line"><span>  │  ✅ Applied to system        │</span></span>
<span class="line"><span>  │  ✅ Committed to git         │</span></span>
<span class="line"><span>  │  ✅ Pushed to GitHub         │</span></span>
<span class="line"><span>  │  ✅ Backed up safely         │</span></span>
<span class="line"><span>  └──────────────────────────────┘</span></span></code></pre></div><h3 id="common-mistake-editing-deployed-files" tabindex="-1">Common Mistake: Editing Deployed Files <a class="header-anchor" href="#common-mistake-editing-deployed-files" aria-label="Permalink to &quot;Common Mistake: Editing Deployed Files&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❌ WRONG WAY (Changes will be lost!)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Edit: ~/.config/zsh/aliases/common.zsh</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─► Changes work temporarily</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─► Next &#39;chezmoi apply&#39; overwrites your changes!</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>✅ CORRECT WAY (Changes are permanent)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Edit: ~/.local/share/chezmoi/private_dot_config/zsh/aliases/common.zsh</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─► Run: chezmoi apply</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─► Commit to git</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─► Changes persist forever!</span></span></code></pre></div><hr><h2 id="quick-reference" tabindex="-1">Quick Reference <a class="header-anchor" href="#quick-reference" aria-label="Permalink to &quot;Quick Reference&quot;">​</a></h2><h3 id="file-location-cheat-sheet" tabindex="-1">File Location Cheat Sheet <a class="header-anchor" href="#file-location-cheat-sheet" aria-label="Permalink to &quot;File Location Cheat Sheet&quot;">​</a></h3><table tabindex="0"><thead><tr><th>What</th><th>Source Location</th><th>Deployed Location</th></tr></thead><tbody><tr><td>Main config</td><td><code>~/.local/share/chezmoi/private_dot_config/zsh/dot_zshrc</code></td><td><code>~/.config/zsh/.zshrc</code></td></tr><tr><td>Common aliases</td><td><code>~/.local/share/chezmoi/private_dot_config/zsh/aliases/common.zsh</code></td><td><code>~/.config/zsh/aliases/common.zsh</code></td></tr><tr><td>Python functions</td><td><code>~/.local/share/chezmoi/private_dot_config/zsh/functions/python-dev.zsh</code></td><td><code>~/.config/zsh/functions/python-dev.zsh</code></td></tr><tr><td>Oh-My-Zsh config</td><td><code>~/.local/share/chezmoi/private_dot_config/zsh/config/10-omz.zsh</code></td><td><code>~/.config/zsh/config/10-omz.zsh</code></td></tr><tr><td>Secrets</td><td><code>~/.local/share/chezmoi/private_dot_config/zsh/private/secrets.zsh.tmpl</code></td><td><code>~/.config/zsh/private/secrets.zsh</code></td></tr></tbody></table><h3 id="command-cheat-sheet" tabindex="-1">Command Cheat Sheet <a class="header-anchor" href="#command-cheat-sheet" aria-label="Permalink to &quot;Command Cheat Sheet&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Task</th><th>Command</th></tr></thead><tbody><tr><td>Edit file</td><td><code>dotfiles edit &lt;file&gt;</code></td></tr><tr><td>Preview changes</td><td><code>chezmoi diff</code></td></tr><tr><td>Apply changes</td><td><code>chezmoi apply</code></td></tr><tr><td>Reload shell</td><td><code>exec zsh</code></td></tr><tr><td>Check status</td><td><code>dotfiles status</code></td></tr><tr><td>Go to source</td><td><code>cd ~/.local/share/chezmoi</code></td></tr><tr><td>Commit changes</td><td><code>git add . &amp;&amp; git commit &amp;&amp; git push</code></td></tr></tbody></table><hr><p><strong>Last Updated</strong>: 2025-01-03 <strong>View Online</strong>: Run <code>dotfiles docs architecture</code></p>`,48)])])}const u=n(l,[["render",i]]);export{m as __pageData,u as default};
